-- Conferencias esperadas apos a carga:
SELECT COUNT(*) AS categorias FROM `categorias`;
SELECT COUNT(*) AS produtos FROM `produtos`;
SELECT COUNT(*) AS movimentacoes_estoque FROM `movimentacoes_estoque`;
